import{_ as r,o,c as t,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"39. Recall Return To Workplace","description":"","frontmatter":{"title":"39. Recall Return To Workplace","eba":"Doctors in Training 2022-2026","topics":["hours","rosters","on-call","allowances"]},"headers":[],"relativePath":"ebas/doctors-in-training/hours-of-work/39-recall-return-to-workplace.md","filePath":"ebas/doctors-in-training/hours-of-work/39-recall-return-to-workplace.md"}'),n={name:"ebas/doctors-in-training/hours-of-work/39-recall-return-to-workplace.md"};function l(s,e,i,c,h,p){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="_39-recall-return-to-workplace" tabindex="-1">39. Recall Return To Workplace <a class="header-anchor" href="#_39-recall-return-to-workplace" aria-label="Permalink to &quot;39. Recall Return To Workplace&quot;">​</a></h1><p><strong>39.1</strong> The provisions of this clause 39 are to be read in conjunction with <a href="/eba/ebas/doctors-in-training/hours-of-work/38-on-call.html">clause 38</a> (On-Call) and <a href="/eba/ebas/doctors-in-training/allowances/55-travelling-allowance-use-of-private-vehicle.html">clause 55</a> (Travelling Allowance – Use of Private Motor Vehicle)</p><p><strong>39.2</strong> Entitlement</p><p><strong>(a)</strong> A Doctor who is recalled to duty outside rostered hours of duty must be paid for the actual time worked, including time reasonably spent in travelling to and return from work, as follows:</p><p><strong>(i)</strong> 1.5 times the ordinary hourly rate of pay for the first two hours; and then</p><p><strong>(ii)</strong> double the ordinary hourly rate of pay for all additional hours.</p><p><strong>39.3</strong> Calculation</p><p><strong>(a)</strong> Each recall must stand alone, with a minimum payment of three hours per recall, except as follows:</p><p><strong>(i)</strong> Where a Doctor has been recalled to duty, a further recall payment cannot occur within the initial three hour period except where the Doctor has left the vicinity of the hospital and/or returned to his/her place of residence.</p><p><strong>(b)</strong> Recall can only occur where the Doctor is rostered on-call and where an authorised Senior Officer of the Health Service has given authority for the recall. This subclause does not apply where there is a genuine medical emergency or disaster.</p><p><strong>(c)</strong> Where a Doctor is recalled for more than 10 hours the Doctor must receive 24 hours free from duty, paid or unpaid according to the roster or the projected roster.</p><p><strong>(d)</strong> Recall payments must not apply to Doctors who receive payment on a percentage of fees generated basis for out of hours work whilst on Rotation to a General Practice Training Program pursuant to <a href="/eba/ebas/doctors-in-training/doctor-employment/31-rotation-to-a-general-practice-training-program.html">clause 31</a> (Rotation to a General Practice Training Program).</p>',12)])])}const g=r(n,[["render",l]]);export{d as __pageData,g as default};
